  ('social-worker-moex-02851', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '問題解決學派社會工作的基本步驟，除了有4P元素（通則）用於個案的處理之外，尚需兼顧MCO的評 定（Assessment）考量，請問前述評定內容是那些？', '["動機（motivation）、案主期待（hope）、能量（capacities）、機會（opportunities）", "移動（movement）、信心（confidence）、權能（empowerment）", "動機（motivation）、信心（confidence）、權能（empowerment）", "移動（movement）、案主期待（hope）、能量（capacities）、機會（opportunities）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
